CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`partner`.`publisher` (
    `publisher_id` BIGINT COMMENT 'Surrogate primary key for the music publisher.',
    `partner_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.partner_agreement. Business justification: Music publishers are partners governed by partner agreements for performance royalty routing. Linking publisher to partner_agreement establishes the governing agreement context.',
    `partner_id` BIGINT COMMENT 'FK to the partner master record for this publisher.',
    `pro_affiliation_id` BIGINT COMMENT 'Performing rights organisation affiliation.',
    `active_flag` BOOLEAN COMMENT 'Whether the publisher relationship is currently active.',
    `admin_share_pct` DECIMAL(18,2) COMMENT '',
    `contact_email` STRING COMMENT 'Primary contact email.',
    `contact_name` STRING COMMENT '',
    `contact_phone` STRING COMMENT 'Publisher contact phone.',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `created_timestamp` TIMESTAMP COMMENT '',
    `ipi_number` STRING COMMENT 'Interested Party Information (IPI/CAE) number identifying the publisher.',
    `is_active_flag` BOOLEAN COMMENT '',
    `publisher_name` STRING COMMENT 'Legal name of the music publisher.',
    `ownership_share_pct` DECIMAL(18,2) COMMENT 'Percentage ownership share of the publishing rights.',
    `ownership_share_percent` DECIMAL(18,2) COMMENT 'Default ownership share percentage.',
    `publisher_type` STRING COMMENT 'Type of publisher (major, independent, sub-publisher, administrator).',
    `registration_date` DATE COMMENT '',
    `source_code` STRING COMMENT 'Source record identifier for medallion lineage.',
    `territory` STRING COMMENT 'Territory in which the publisher controls the rights.',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp.',
    `updated_timestamp` TIMESTAMP COMMENT '',
    CONSTRAINT pk_publisher PRIMARY KEY(`publisher_id`)
) COMMENT 'Music publisher master for performance royalty routing.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`partner`.`music_label` (
    `music_label_id` BIGINT COMMENT 'Primary key for music_label',
    `partner_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.partner_agreement. Business justification: Music labels are partners with sync licensing and royalty agreements. Linking music_label to partner_agreement establishes the governing agreement context for label relationships.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to partner.vendor. Business justification: Music labels are a type of vendor/partner in the media broadcasting context — they provide music content under licensing agreements. Linking music_label to vendor establishes the vendor relationship f',
    `parent_music_label_id` BIGINT COMMENT 'Self-referencing FK on music_label (parent_music_label_id)',
    `active_agreement_count` STRING COMMENT 'Number of currently active licensing or distribution agreements between the broadcaster and this music label, used for partner relationship health monitoring and contract renewal tracking.',
    `bank_account_ref` STRING COMMENT 'Masked or tokenised reference to the music labels bank account details held in the secure payment vault, used to route royalty wire transfers. Full account details are stored in the payment vault system, not in this table.',
    `blanket_licence_available` BOOLEAN COMMENT 'Indicates whether the music label offers a blanket licence arrangement covering all or a defined subset of its catalogue for broadcast use, as opposed to requiring per-track clearance. Blanket licences simplify music clearance for high-volume broadcast operations.',
    `blanket_licence_fee_annual` DECIMAL(18,2) COMMENT 'Annual fee payable to the music label for a blanket broadcast licence covering the labels catalogue, expressed in the labels billing currency. Applicable only when blanket_licence_available is True.',
    `catalogue_size` STRING COMMENT 'Approximate number of master recordings in the labels active catalogue available for licensing, used for rights clearance capacity planning and partner tier classification.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the country where the music label is incorporated or primarily operates, used for territorial rights management and royalty remittance routing.',
    `created_at` TIMESTAMP COMMENT 'Timestamp when this music label record was first created in the data platform, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports medallion-layer lineage tracing per VREQ-035 cross-domain timestamp/lineage standard.',
    `digital_distribution_rights` BOOLEAN COMMENT 'Indicates whether the label holds digital distribution rights for its catalogue, relevant for FAST channel, SVOD, and AVOD monetisation scenarios where music clearance for digital platforms is required.',
    `do_not_use_flag` BOOLEAN COMMENT 'Indicates that this music label is currently embargoed or restricted from use in new productions or broadcasts, due to legal disputes, sanctions, or compliance holds. When True, the labels catalogue must not be cleared for new use.',
    `fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the music label invoices synchronisation and master use licence fees (e.g., USD, GBP, EUR).',
    `genre_focus` STRING COMMENT 'Primary music genre(s) associated with the labels catalogue, used for rights clearance routing and music licensing analytics (e.g., Pop, Hip-Hop, Classical, Country). [ENUM-REF-CANDIDATE: pop|hip_hop|rock|country|classical|jazz|electronic|r_and_b|latin|gospel|world — promote to reference product]',
    `isni` STRING COMMENT 'ISO 27729 International Standard Name Identifier (ISNI) assigned to the music label as a legal entity, enabling unambiguous identification across global rights databases and metadata exchanges.',
    `label_code` STRING COMMENT 'Externally-known short alphanumeric code uniquely identifying the music label, used in licensing, royalty reporting, and rights clearance workflows (e.g., UNIV, SONY-MUSIC, WMG).',
    `label_name` STRING COMMENT 'Full legal or trading name of the music label as registered with performing rights organisations and licensing bodies (e.g., Universal Music Group, Atlantic Records).',
    `label_short_name` STRING COMMENT 'Abbreviated or commonly-used trading name of the music label for display in broadcast schedules, cue sheets, and on-screen credits (e.g., Atlantic, Def Jam).',
    `label_status` STRING COMMENT 'Current operational lifecycle status of the music label. Active labels are available for new licensing; dissolved or acquired labels may still hold legacy rights requiring clearance.',
    `label_type` STRING COMMENT 'Classification of the label within the music industry structure. Major labels are the Big Three (Universal, Sony, Warner); independent labels operate outside major group ownership; sub-labels are imprints of a parent; vanity labels are artist-owned imprints distributed by a major.',
    `last_agreement_date` DATE COMMENT 'Date of the most recently executed licensing or distribution agreement with this music label, used for relationship recency analysis and renewal pipeline management.',
    `lei_code` STRING COMMENT 'ISO 17442 Legal Entity Identifier (LEI) code for the music labels legal entity, used in financial reporting, royalty remittance, and regulatory compliance filings.',
    `licensing_contact_email` STRING COMMENT 'Dedicated email address for the music labels licensing department, used specifically for synchronisation licence requests, broadcast clearance, and master use licence applications.',
    `master_rights_holder` BOOLEAN COMMENT 'Indicates whether this label is the master recording rights holder (as opposed to a publishing or distribution-only entity). True = label owns master rights; False = label is a distributor or sub-licensor only. Drives clearance workflow routing.',
    `mechanical_rights_org` STRING COMMENT 'Name of the mechanical rights licensing organisation that administers mechanical royalties on behalf of the label (e.g., MLC, Harry Fox Agency, MCPS, CMRRA). Relevant for synchronisation and broadcast licensing.',
    `next_renewal_date` DATE COMMENT 'Date on which the next licensing agreement with this music label is due for renewal or renegotiation, used to trigger advance notice workflows and renewal pipeline reporting.',
    `notes` STRING COMMENT 'Free-text field for capturing additional operational notes about the music label, such as special clearance instructions, preferred communication protocols, or historical relationship context not captured in structured fields.',
    `onboarding_date` DATE COMMENT 'Date on which the music label was formally onboarded as a licensed partner in the broadcasters rights management system, marking the start of the commercial relationship.',
    `parent_label_name` STRING COMMENT 'Name of the parent or major label that owns or controls this label, supporting hierarchical label group reporting (e.g., Universal Music Group as parent of Interscope Records).',
    `payment_terms_days` STRING COMMENT 'Number of days from invoice date within which royalty payments or licence fees must be remitted to the music label (e.g., 30, 45, 60), per the agreed payment terms.',
    `preferred_payment_method` STRING COMMENT 'The music labels preferred method for receiving royalty and licence fee payments, used to configure automated payment runs in the accounts payable system.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary business contact at the music label for licensing and sync clearance communications.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact at the music label responsible for licensing negotiations, sync clearance requests, and royalty dispute resolution.',
    `primary_contact_phone` STRING COMMENT 'Phone number of the primary business contact at the music label, used for urgent sync clearance and licensing negotiations.',
    `pro_affiliation` STRING COMMENT 'Name of the Performing Rights Organisation (PRO) with which the label is affiliated for public performance royalty collection (e.g., ASCAP, BMI, SESAC, PRS, SOCAN). [ENUM-REF-CANDIDATE: ASCAP|BMI|SESAC|PRS|SOCAN|APRA|SABAM|GEMA|SACEM — promote to reference product]',
    `publishing_rights_holder` BOOLEAN COMMENT 'Indicates whether this label also controls publishing (composition) rights in addition to master recording rights. Relevant for one-stop licensing scenarios where both sync and master use licences are obtained from the same entity.',
    `registered_address_city` STRING COMMENT 'City of the music labels official registered business address.',
    `registered_address_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country of the music labels registered business address, used for withholding tax treaty determination.',
    `registered_address_line1` STRING COMMENT 'First line of the music labels official registered business address, used for royalty remittance, contract correspondence, and regulatory filings.',
    `relationship_tier` STRING COMMENT 'Classification of the broadcasters commercial relationship with the music label, used to prioritise licensing negotiations, assign account management resources, and determine escalation paths for clearance disputes.',
    `royalty_rate_percent` DECIMAL(18,2) COMMENT 'Standard royalty rate percentage applied to broadcast revenue or licence fees payable to the music label for use of its master recordings, expressed as a decimal percentage (e.g., 5.2500 = 5.25%).',
    `sanctions_screened_date` DATE COMMENT 'Date on which the music label was most recently screened against applicable sanctions lists (OFAC SDN, EU Consolidated List, UN Sanctions), required for AML/KYC compliance in royalty payment processing.',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this music label record was ingested (e.g., RIGHTS_MGT, PARTNER_PORTAL, MANUAL). Supports medallion-layer lineage tracing per VREQ-035 cross-domain timestamp/lineage standard.',
    `source_system_code` STRING COMMENT 'Identifier of this music label record in the originating source system, enabling bidirectional traceability between the lakehouse silver layer and the operational system of record. Supports medallion bronze-to-silver lineage per VREQ-035.',
    `standard_sync_fee` DECIMAL(18,2) COMMENT 'Standard base synchronisation licence fee charged by the label for a single broadcast use of a master recording, expressed in the labels billing currency. Used as a baseline for negotiation and budget estimation.',
    `sync_licence_turnaround_days` STRING COMMENT 'Standard number of business days the label commits to for responding to synchronisation licence requests, used in SLA tracking for broadcast production clearance workflows.',
    `sync_licensing_url` STRING COMMENT 'URL of the music labels online synchronisation licensing portal or submission form, enabling broadcast teams to submit sync clearance requests directly.',
    `tax_identification_number` STRING COMMENT 'Government-issued tax identification number (EIN, VAT number, or equivalent) for the music labels legal entity, required for royalty withholding tax compliance and 1099/1042-S reporting.',
    `tax_treaty_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the tax treaty jurisdiction applicable to this music label, determining the reduced withholding tax rate on royalty payments.',
    `territory_scope` STRING COMMENT 'Geographic scope of the labels licensing authority, expressed as a pipe-delimited list of ISO 3166-1 alpha-3 country codes or the value WORLDWIDE for global rights holders. Drives territorial rights clearance logic.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp when this music label record was most recently updated in the data platform, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports medallion-layer lineage tracing per VREQ-035 cross-domain timestamp/lineage standard.',
    `w8_ben_e_on_file` BOOLEAN COMMENT 'Indicates whether a valid IRS Form W-8BEN-E (Certificate of Foreign Status of Beneficial Owner) is on file for this music label, required for reduced withholding tax treatment on US-source royalty payments.',
    `w8_expiry_date` DATE COMMENT 'Expiry date of the IRS Form W-8BEN-E on file for this music label. W-8 forms are generally valid for three calendar years; expired forms require renewal before royalty payments can be processed at reduced withholding rates.',
    `withholding_tax_rate_percent` DECIMAL(18,2) COMMENT 'Applicable withholding tax rate percentage to be deducted from royalty payments to the music label, based on the labels country of domicile and applicable tax treaty (e.g., 0.0000 for treaty-exempt, 30.0000 for default US rate).',
    CONSTRAINT pk_music_label PRIMARY KEY(`music_label_id`)
) COMMENT 'Master reference table for music_label. Referenced by label_id.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`partner`.`partner` (
    `partner_id` BIGINT COMMENT 'Primary key for partner',
    `employee_id` BIGINT COMMENT 'Internal employee identifier of the broadcasters account manager or relationship owner responsible for managing this partner relationship.',
    `parent_partner_id` BIGINT COMMENT 'Self-referencing identifier pointing to the parent partner record, enabling hierarchical modelling of corporate family trees (e.g., subsidiary to parent studio).',
    `tax_code_id` BIGINT COMMENT 'Government-issued Tax Identification Number (TIN) or Employer Identification Number (EIN) for the partner, used for tax reporting, withholding, and regulatory compliance.',
    `ultimate_parent_partner_id` BIGINT COMMENT 'Self-referencing identifier pointing to the topmost ultimate parent partner record in the corporate hierarchy, enabling group-level deal aggregation and compliance checks.',
    `assigned_business_unit` STRING COMMENT 'Name or code of the internal business unit (e.g., Content Acquisition, Distribution, Ad Sales) primarily responsible for managing the partner relationship.',
    `billing_contact_email` STRING COMMENT 'Email address designated for billing, invoicing, and accounts payable/receivable communications with the partner.',
    `content_genres` STRING COMMENT 'Comma-separated list of primary content genres the partner specialises in (e.g., drama, news, sports, documentary), used for content acquisition targeting and scheduling alignment.',
    `country_of_incorporation` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction in which the partner is legally incorporated or registered.',
    `created_at` TIMESTAMP COMMENT 'Timestamp (ISO 8601 with timezone) when this partner record was first created in the data platform. Supports medallion bronze-to-silver lineage tracing per VREQ-035.',
    `credit_limit` DECIMAL(18,2) COMMENT 'Maximum outstanding receivable balance (in preferred currency) approved for this partner before new transactions are placed on hold, used by finance for credit risk management.',
    `credit_rating` STRING COMMENT 'Internal or external credit rating assigned to the partner (e.g., AAA, BB+, or internal score), used for deal approval thresholds and payment term negotiations.',
    `data_sharing_consent` BOOLEAN COMMENT 'Indicates whether the partner has provided consent for the broadcaster to share partner data with third parties as part of co-marketing or analytics programmes.',
    `distribution_platforms` STRING COMMENT 'Comma-separated list of distribution platforms the partner operates on or supports (e.g., linear_tv, svod, avod, fast, cable, satellite), informing deal structuring and rights negotiations.',
    `duns_number` STRING COMMENT 'Nine-digit Dun & Bradstreet Data Universal Numbering System (DUNS) identifier for the partner organisation, used for credit assessment and vendor verification.',
    `is_sanctioned` BOOLEAN COMMENT 'Indicates whether the partner appears on any government or regulatory sanctions list (e.g., OFAC SDN, EU Consolidated List), blocking new deal execution.',
    `kyc_verified` BOOLEAN COMMENT 'Indicates whether the partner has completed the broadcasters Know Your Customer (KYC) due diligence process, a prerequisite for contract execution.',
    `kyc_verified_date` DATE COMMENT 'Date on which the partners Know Your Customer (KYC) verification was last completed or renewed.',
    `legal_contact_email` STRING COMMENT 'Email address designated for legal, compliance, and contract-related communications with the partner.',
    `legal_name` STRING COMMENT 'Full registered legal name of the partner organisation as it appears on contracts, regulatory filings, and official correspondence.',
    `lei_code` STRING COMMENT '20-character ISO 17442 Legal Entity Identifier (LEI) code for the partner, used in financial regulatory reporting and cross-border transaction identification.',
    `msa_effective_date` DATE COMMENT 'Date on which the Master Services Agreement (MSA) with the partner became legally effective.',
    `msa_executed` BOOLEAN COMMENT 'Indicates whether a Master Services Agreement (MSA) or Master Licensing Agreement has been fully executed with this partner, establishing the overarching commercial framework.',
    `msa_expiry_date` DATE COMMENT 'Date on which the Master Services Agreement (MSA) with the partner expires. Null indicates an open-ended agreement.',
    `nda_executed` BOOLEAN COMMENT 'Indicates whether a Non-Disclosure Agreement (NDA) has been fully executed with this partner, required before sharing confidential content or deal information.',
    `nda_expiry_date` DATE COMMENT 'Date on which the executed Non-Disclosure Agreement (NDA) with the partner expires, triggering a renewal workflow.',
    `notes` STRING COMMENT 'Free-text field for internal notes, relationship context, or special handling instructions relevant to the partner, visible only to authorised internal users.',
    `onboarding_status` STRING COMMENT 'Tracks the progress of the partner through the broadcasters onboarding workflow, including KYC, compliance checks, and contract execution.',
    `ownership_structure` STRING COMMENT 'Classification of the partners ownership structure, relevant for regulatory compliance, FCC ownership rules, and deal approval workflows.',
    `parent_company_name` STRING COMMENT 'Legal name of the ultimate parent or holding company of the partner, used for corporate hierarchy analysis, consolidated deal management, and conflict-of-interest checks.',
    `partner_code` STRING COMMENT 'Externally-known alphanumeric business identifier assigned to the partner, used in contracts, invoices, and inter-system references. Unique across all partner records.',
    `partner_subtype` STRING COMMENT 'Secondary classification providing finer granularity within the partner_type (e.g., cable_operator under MVPD, major_studio under studio). [ENUM-REF-CANDIDATE: promote to reference product]',
    `partner_type` STRING COMMENT 'Categorical classification of the partners primary business role in relation to the broadcaster. [ENUM-REF-CANDIDATE: studio|syndicator|content_provider|mvpd|distributor|co_producer|affiliate|agency|technology_vendor|other — promote to reference product]',
    `payment_terms_days` STRING COMMENT 'Standard number of days from invoice date within which the partner is expected to remit payment, as agreed in the master partner agreement (e.g., Net 30, Net 60).',
    `preferred_currency` STRING COMMENT 'ISO 4217 three-letter currency code representing the partners preferred billing and payment currency for contract and invoice processing.',
    `preferred_delivery_format` STRING COMMENT 'Partners preferred technical format for content delivery and exchange (e.g., AS-11, MXF, MOV, MP4), used to configure delivery pipelines and ingest workflows.',
    `preferred_delivery_method` STRING COMMENT 'Partners preferred method for physical or digital content delivery (e.g., Aspera, SFTP, cloud storage, satellite), used to configure delivery workflows.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary business contact at the partner organisation, used for operational and contractual communications.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact person at the partner organisation for day-to-day operational communications.',
    `primary_contact_phone` STRING COMMENT 'Primary telephone number for the partners main business contact, including country dialling code.',
    `primary_operating_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where the partner primarily conducts its media broadcasting operations.',
    `registered_address_city` STRING COMMENT 'City of the partners official registered business address.',
    `registered_address_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the partners official registered business address.',
    `registered_address_line1` STRING COMMENT 'First line of the partners official registered business address, used for legal correspondence and regulatory filings.',
    `registered_address_postal_code` STRING COMMENT 'Postal or ZIP code of the partners official registered business address.',
    `relationship_category` STRING COMMENT 'Defines the commercial relationship category between the broadcaster and the partner from a rights and finance perspective (e.g., licensor, licensee, co-producer).',
    `relationship_end_date` DATE COMMENT 'Date on which the commercial relationship with the partner was formally terminated. Null indicates an ongoing relationship.',
    `relationship_start_date` DATE COMMENT 'Date on which the commercial relationship with the partner was formally established, used for tenure analysis and anniversary-based contract reviews.',
    `source_id` STRING COMMENT 'The native record identifier of this partner in the originating source system, enabling bi-directional reconciliation between the lakehouse and operational systems.',
    `source_system` STRING COMMENT 'Name or code of the operational system of record from which this partner record was originated or last updated (e.g., CRM, rights management system, ERP), supporting medallion lineage tracing.',
    `partner_status` STRING COMMENT 'Current lifecycle status of the partner record, governing whether the partner can be engaged in new deals, orders, or content acquisitions.',
    `termination_reason` STRING COMMENT 'Reason code for the termination of the partner relationship, used for post-mortem analysis and regulatory reporting.',
    `tier` STRING COMMENT 'Commercial tier classification indicating the strategic importance and service level of the partner relationship (e.g., strategic, preferred, standard).',
    `trade_name` STRING COMMENT 'Operating or doing business as (DBA) name of the partner, which may differ from the legal name. Used in day-to-day communications and branding.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp (ISO 8601 with timezone) when this partner record was last modified in the data platform. Supports medallion bronze-to-silver lineage tracing per VREQ-035.',
    `vat_registration_number` STRING COMMENT 'Value Added Tax (VAT) registration number for the partner, required for EU and international tax compliance on content licensing and distribution transactions.',
    CONSTRAINT pk_partner PRIMARY KEY(`partner_id`)
) COMMENT 'Master reference table for partner. ';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`partner`.`partner_partner` (
    `partner_id` BIGINT COMMENT 'Primary key for partner_partner',
    `account_manager_name` STRING COMMENT 'Name of the internal account manager or relationship owner responsible for managing this partner relationship. Business reference field, not direct PII of an external party.',
    `api_integration_enabled` BOOLEAN COMMENT 'Indicates whether the partner has an active API integration with the broadcasters systems for automated content metadata exchange, rights queries, or scheduling feeds.',
    `billing_email` STRING COMMENT 'Email address designated for invoice delivery, payment remittance advice, and billing dispute correspondence.',
    `created_at` TIMESTAMP COMMENT 'Timestamp when this partner record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports medallion lineage tracing per VREQ-035.',
    `credit_limit` DECIMAL(18,2) COMMENT 'Maximum outstanding receivable balance approved for this partner before new deal execution or content delivery is placed on hold. Expressed in the remittance_currency.',
    `credit_rating` STRING COMMENT 'Internal or third-party credit rating assigned to the partner (e.g., A, BBB+, High Risk), used to govern deal approval thresholds and payment terms.',
    `distribution_platform` STRING COMMENT 'Primary distribution platform or channel type through which this partner delivers or receives content (e.g., linear broadcast, VOD, SVOD, FAST, OTT). [ENUM-REF-CANDIDATE: promote to reference product]',
    `diversity_certification` STRING COMMENT 'Diversity certification status of the partner organisation (e.g., Minority Business Enterprise (MBE), Women Business Enterprise (WBE), Veteran Business Enterprise (VBE)), used for supplier diversity reporting and FCC EEO compliance.',
    `duns_number` STRING COMMENT 'Nine-digit Dun & Bradstreet Data Universal Numbering System (DUNS) identifier for the partner organisation, used for credit checks, vendor onboarding, and global entity resolution.',
    `edi_capable` BOOLEAN COMMENT 'Indicates whether the partner supports Electronic Data Interchange (EDI) for automated exchange of purchase orders, invoices, and advance ship notices.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether any active agreement with this partner contains exclusivity provisions that restrict the broadcaster from engaging competing partners in the same category.',
    `first_deal_date` DATE COMMENT 'Date of the first executed commercial agreement with this partner, used for relationship tenure analytics and partner lifecycle reporting.',
    `incorporation_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction where the partner is legally incorporated or registered.',
    `incorporation_state` STRING COMMENT 'State or province of incorporation for domestic entities (e.g., DE for Delaware, CA for California), relevant for US legal entity classification and tax nexus.',
    `legal_name` STRING COMMENT 'Full legal registered name of the partner organisation as it appears on contracts, licensing agreements, and regulatory filings.',
    `lei_code` STRING COMMENT '20-character ISO 17442 Legal Entity Identifier (LEI) for the partner, required for financial counterparty identification under Dodd-Frank and EMIR reporting.',
    `mfn_eligible` BOOLEAN COMMENT 'Indicates whether this partner is entitled to Most Favoured Nation (MFN) pricing protections, meaning they must receive terms no less favourable than those offered to any comparable partner.',
    `nda_expiry_date` DATE COMMENT 'Expiration date of the NDA on file with this partner. Triggers legal review and renewal workflow.',
    `nda_on_file` BOOLEAN COMMENT 'Indicates whether a valid Non-Disclosure Agreement (NDA) is executed and on file with this partner, required before sharing confidential content, ratings, or financial data.',
    `notes` STRING COMMENT 'Free-text field for internal notes, relationship context, or special handling instructions relevant to this partner. Confidential and restricted to authorised relationship management personnel.',
    `onboarding_date` DATE COMMENT 'Date on which the partner completed the onboarding process and became eligible for active deal execution and content exchange.',
    `parent_partner_id` BIGINT COMMENT 'Self-referencing foreign key to the parent partner record, enabling hierarchical modelling of corporate families (e.g., subsidiary to parent studio, regional affiliate to national MVPD).',
    `partner_code` STRING COMMENT 'Externally-known, human-readable unique business identifier assigned to the partner (e.g., studio code, syndicator code, MVPD affiliate code). Used in contracts, invoices, and inter-system references.',
    `partner_status` STRING COMMENT 'Current lifecycle status of the partner relationship. Drives eligibility for new deal creation, content delivery, and payment processing.',
    `partner_subtype` STRING COMMENT 'Secondary classification providing finer granularity within the partner_type (e.g., cable_mvpd, satellite_mvpd, vMVPD, premium_studio, indie_studio). [ENUM-REF-CANDIDATE: promote to reference product]',
    `partner_type` STRING COMMENT 'Categorical classification of the partners primary business role in relation to the broadcaster. [ENUM-REF-CANDIDATE: studio|syndicator|content_provider|mvpd|ott_platform|co_producer|affiliate|distributor|agency — promote to reference product]',
    `payment_terms` STRING COMMENT 'Standard payment terms agreed with the partner governing invoice due dates (e.g., Net 30, Net 60). Drives accounts payable/receivable scheduling.',
    `preferred_delivery_format` STRING COMMENT 'Partners preferred technical format for content delivery or receipt (e.g., MXF, IMF, ProRes, HLS). Used to configure automated delivery pipelines and QC workflows.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary business contact at the partner organisation, used for deal communications, content delivery notifications, and compliance correspondence.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact at the partner organisation responsible for day-to-day relationship management.',
    `primary_contact_phone` STRING COMMENT 'Primary telephone number for the partner contact, including country code where applicable.',
    `primary_content_genre` STRING COMMENT 'Primary genre category of content supplied or distributed by this partner (e.g., drama, news, sports, documentary). Used for content acquisition planning and genre-based partner segmentation. [ENUM-REF-CANDIDATE: promote to reference product]',
    `registered_address_city` STRING COMMENT 'City of the partners registered business address.',
    `registered_address_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the partners registered business address.',
    `registered_address_line1` STRING COMMENT 'First line of the partners official registered business address, used for legal notices, contract execution, and regulatory filings.',
    `registered_address_postal_code` STRING COMMENT 'Postal or ZIP code of the partners registered business address.',
    `registered_address_state` STRING COMMENT 'State or province of the partners registered business address, used for tax nexus determination and legal jurisdiction.',
    `relationship_tier` STRING COMMENT 'Commercial tier classification indicating the strategic importance and depth of the partner relationship, used to prioritise deal terms, SLAs, and executive engagement.',
    `remittance_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the partner expects to receive or make payments (e.g., USD, GBP, EUR).',
    `sanctions_last_screened_date` DATE COMMENT 'Date on which the most recent sanctions screening was performed for this partner. Triggers periodic re-screening workflow per compliance policy.',
    `sanctions_screened` BOOLEAN COMMENT 'Indicates whether the partner has been screened against OFAC, EU, and UN sanctions lists as part of the onboarding and periodic compliance review process.',
    `source_id` STRING COMMENT 'Native identifier of this partner record in the originating source system, enabling bi-directional reconciliation and lineage tracing across bronze-silver-gold medallion layers per VREQ-035.',
    `source_system` STRING COMMENT 'Name or code of the operational system of record from which this partner record was originated or last updated (e.g., SAP_VENDOR, SALESFORCE_CRM, RIGHTS_MGT_SYSTEM). Supports medallion lineage tracing per VREQ-035.',
    `tax_id` STRING COMMENT 'Federal or national tax identification number (EIN, VAT number, or equivalent) used for tax reporting, W-9/W-8 compliance, and 1099/1042-S filings.',
    `termination_date` DATE COMMENT 'Date on which the partner relationship was formally terminated. Null for active partners. Used for offboarding workflows and historical reporting.',
    `termination_reason` STRING COMMENT 'Reason code for the termination of the partner relationship, used for churn analysis and post-mortem reporting.',
    `territory_scope` STRING COMMENT 'Geographic territory or market scope in which this partner operates or holds distribution rights (e.g., USA, DOMESTIC, WORLDWIDE). Informs rights clearance and deal structuring.',
    `trade_name` STRING COMMENT 'Doing-business-as (DBA) or brand name used in day-to-day commercial interactions, distinct from the legal registered name.',
    `ultimate_parent_partner_id` BIGINT COMMENT 'Reference to the top-level ultimate parent entity in the corporate hierarchy, used for consolidated reporting, credit exposure, and group-level deal aggregation.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp when this partner record was most recently modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change detection and medallion lineage tracing per VREQ-035.',
    `w9_expiry_date` DATE COMMENT 'Expiration date of the W-9 or W-8 tax form on file. Triggers renewal workflow to maintain payment eligibility and IRS compliance.',
    `w9_on_file` BOOLEAN COMMENT 'Indicates whether a valid IRS Form W-9 (or W-8 for foreign entities) has been received and is on file, required before issuing payments to US-based partners.',
    CONSTRAINT pk_partner_partner PRIMARY KEY(`partner_id`)
) COMMENT 'Master reference table for partner_partner. ';

